from vex import verify

@verify(
    checks=[
        "retrieval.relevance > 0.8",
        "context.completeness.score > 0.9",
        "temporal.freshness < 24h"
    ],
    rollback=True
)
def safe_query(query_engine, query: str):
    response = query_engine.query(query)
    return {
        'response': response.response,
        'source_nodes': [n.get_content() for n in response.source_nodes]
    }

# Usage in workflow
verified_context = safe_query(query_engine, "payment approval process")
agent_response = await agent.chat(verified_context['response'])

