import { verify } from '@vex/sdk';

const vexMiddleware = verify({
  checks: [
    'retrieval.relevance > 0.8',
    'permissions.userHasScope("workflows:execute")',
    'action.idempotent'
  ],
  rollback: true,
  audience: 'ops-team'
});

app.post('/workflow/execute', vexMiddleware, async (req, res) => {
  const { query, userId } = req.body;

  // LlamaIndex query through verified middleware
  const context = await queryEngine.query({ query });

  const agentResult = await agent.chat({
    message: query,
    context: context.toString(),
    userId
  });

  res.json({ result: agentResult });
});
